/** Type checker for Typed Jam (Assignment 5).
  * Implements ASTVisitor<JamType>, walking the AST to verify type correctness.
  * Throws TypeException on any type error. */

import java.util.*;

/** Exception thrown when a type error is detected. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** A binding in the type environment, associating a Variable with its JamType. */
class TypeBinding implements WithVariable {
  private Variable var;
  private JamType type;
  TypeBinding(Variable v, JamType t) { var = v; type = t; }
  public Variable var() { return var; }
  public JamType type() { return type; }
}

/** Type checker visitor: takes a type environment and returns a JamType for each AST node. */
class TypeChecker implements ASTVisitor<JamType> {

  /** The current type environment. */
  private PureList<TypeBinding> typeEnv;

  /** Constructs a TypeChecker with the given type environment. */
  TypeChecker(PureList<TypeBinding> env) { typeEnv = env; }

  /** Constructs a TypeChecker with an empty environment. */
  TypeChecker() { typeEnv = new Empty<TypeBinding>(); }

  /** Returns a new TypeChecker with an extended environment. */
  private TypeChecker extend(PureList<TypeBinding> env) {
    return new TypeChecker(env);
  }

  /* ---- Visitor methods ---- */

  public JamType forBoolConstant(BoolConstant b) { return BoolType.ONLY; }
  public JamType forIntConstant(IntConstant i)   { return IntType.ONLY; }

  /** Typed empty list (empty: T) has type list T. */
  @Override
  public JamType forTypedEmptyConstant(TypedEmptyConstant n) {
    return new ListType(n.elemType());
  }

  /** Bare 'empty' without a type annotation is a type error in typed Jam. */
  public JamType forEmptyConstant(EmptyConstant n) {
    throw new TypeException("'empty' must have a type annotation (write 'empty: Type')");
  }

  /** Looks up the variable's type in the environment. */
  public JamType forVariable(Variable v) {
    TypeBinding match = typeEnv.accept(new LookupVisitor<TypeBinding>(v));
    if (match == null) throw new TypeException("Unbound variable: " + v);
    return match.type();
  }

  /** Naked primitive functions cannot appear as values. */
  public JamType forPrimFun(PrimFun f) {
    throw new TypeException("Primitive '" + f + "' cannot be used as a value");
  }

  /** Type checks a unary operator application. */
  public JamType forUnOpApp(UnOpApp u) {
    JamType argType = u.arg().accept(this);
    return u.rator().accept(new UnOpTypeVisitor(argType));
  }

  /** Type checks a binary operator application. */
  public JamType forBinOpApp(BinOpApp b) {
    return b.rator().accept(new BinOpTypeVisitor(b.arg1(), b.arg2()));
  }

  /** Type checks a function or primitive application. */
  public JamType forApp(App a) {
    AST rator = a.rator();
    AST[] args = a.args();

    /* Polymorphic primitive functions: type-check specially */
    if (rator instanceof PrimFun) {
      return typePrimApp((PrimFun) rator, args);
    }

    /* Non-primitive: rator must have a function type */
    JamType ratorType = rator.accept(this);
    if (!(ratorType instanceof FunType))
      throw new TypeException("Applied expression '" + rator + "' has non-function type " + ratorType);
    FunType ft = (FunType) ratorType;
    JamType[] paramTypes = ft.paramTypes();
    if (paramTypes.length != args.length)
      throw new TypeException("Argument count mismatch: expected " + paramTypes.length + ", got " + args.length);
    for (int i = 0; i < args.length; i++) {
      JamType argType = args[i].accept(this);
      if (!argType.equals(paramTypes[i]))
        throw new TypeException("Argument " + i + " type mismatch: expected " + paramTypes[i] + ", got " + argType);
    }
    return ft.returnType();
  }

  /** Type checks a map (anonymous function), returning its FunType. */
  public JamType forMap(Map m) {
    Variable[] vars  = m.vars();
    JamType[]  types = m.varTypes();
    PureList<TypeBinding> newEnv = typeEnv;
    for (int i = vars.length - 1; i >= 0; i--) {
      if (types[i] == null)
        throw new TypeException("Map parameter '" + vars[i] + "' has no type annotation");
      newEnv = newEnv.cons(new TypeBinding(vars[i], types[i]));
    }
    JamType bodyType = m.body().accept(extend(newEnv));
    return new FunType(types, bodyType);
  }

  /** Type checks if-then-else: condition is bool, branches must match. */
  public JamType forIf(If i) {
    JamType testType = i.test().accept(this);
    if (testType != BoolType.ONLY)
      throw new TypeException("If condition has type " + testType + ", expected bool");
    JamType conseqType = i.conseq().accept(this);
    JamType altType    = i.alt().accept(this);
    if (!conseqType.equals(altType))
      throw new TypeException("If branches have different types: " + conseqType + " vs " + altType);
    return conseqType;
  }

  /** Type checks a recursive let: extends env with declared types, then verifies RHS types. */
  public JamType forLet(Let l) {
    Def[] defs = l.defs();
    /* Build new env with all declared types (recursive: each def can see all vars) */
    PureList<TypeBinding> newEnv = typeEnv;
    for (int i = defs.length - 1; i >= 0; i--) {
      JamType declaredType = defs[i].lhsType();
      if (declaredType == null)
        throw new TypeException("Let variable '" + defs[i].lhs() + "' has no type annotation");
      newEnv = newEnv.cons(new TypeBinding(defs[i].lhs(), declaredType));
    }
    TypeChecker newChecker = extend(newEnv);
    /* Verify each RHS type matches its declared type */
    for (Def def : defs) {
      JamType rhsType      = def.rhs().accept(newChecker);
      JamType declaredType = def.lhsType();
      if (!rhsType.equals(declaredType))
        throw new TypeException("Let variable '" + def.lhs() + "': declared type " + declaredType
            + " does not match rhs type " + rhsType);
    }
    return l.body().accept(newChecker);
  }

  /** Type checks a block: each expression is checked; returns the type of the last. */
  public JamType forBlock(Block b) {
    AST[] exps = b.exps();
    JamType result = null;
    for (AST e : exps) result = e.accept(this);
    return result;
  }

  /* ---- Helper: type check primitive function applications ---- */

  private JamType typePrimApp(PrimFun prim, AST[] args) {
    if (prim == ConsPrim.ONLY) {
      if (args.length != 2) throw new TypeException("cons requires 2 arguments");
      JamType t1 = args[0].accept(this);
      JamType t2 = args[1].accept(this);
      if (!(t2 instanceof ListType))
        throw new TypeException("cons: second argument must be a list, got " + t2);
      JamType elemType = ((ListType) t2).elemType();
      if (!t1.equals(elemType))
        throw new TypeException("cons: element type " + t1 + " does not match list type " + elemType);
      return t2; // list T
    }
    if (prim == FirstPrim.ONLY) {
      if (args.length != 1) throw new TypeException("first requires 1 argument");
      JamType t = args[0].accept(this);
      if (!(t instanceof ListType))
        throw new TypeException("first: argument must be a list, got " + t);
      return ((ListType) t).elemType();
    }
    if (prim == RestPrim.ONLY) {
      if (args.length != 1) throw new TypeException("rest requires 1 argument");
      JamType t = args[0].accept(this);
      if (!(t instanceof ListType))
        throw new TypeException("rest: argument must be a list, got " + t);
      return t; // list T
    }
    if (prim == EmptyPPrim.ONLY) {
      if (args.length != 1) throw new TypeException("empty? requires 1 argument");
      JamType t = args[0].accept(this);
      if (!(t instanceof ListType))
        throw new TypeException("empty?: argument must be a list, got " + t);
      return BoolType.ONLY;
    }
    if (prim == ConsPPrim.ONLY) {
      if (args.length != 1) throw new TypeException("cons? requires 1 argument");
      JamType t = args[0].accept(this);
      if (!(t instanceof ListType))
        throw new TypeException("cons?: argument must be a list, got " + t);
      return BoolType.ONLY;
    }
    throw new TypeException("Unknown primitive: " + prim);
  }

  /* ---- Inner class: unary operator type visitor ---- */

  /** Checks the type of a unary operator given the argument type. */
  class UnOpTypeVisitor implements UnOpVisitor<JamType> {
    private JamType argType;
    UnOpTypeVisitor(JamType t) { argType = t; }

    public JamType forUnOpPlus() {
      if (argType != IntType.ONLY) throw new TypeException("Unary '+' requires int, got " + argType);
      return IntType.ONLY;
    }
    public JamType forUnOpMinus() {
      if (argType != IntType.ONLY) throw new TypeException("Unary '-' requires int, got " + argType);
      return IntType.ONLY;
    }
    public JamType forOpTilde() {
      if (argType != BoolType.ONLY) throw new TypeException("'~' requires bool, got " + argType);
      return BoolType.ONLY;
    }
    /** Dereference: ref 'a -> 'a */
    public JamType forOpBang() {
      if (!(argType instanceof RefType))
        throw new TypeException("'!' requires ref type, got " + argType);
      return ((RefType) argType).elemType();
    }
    /** ref: 'a -> ref 'a */
    public JamType forOpRef() {
      return new RefType(argType);
    }
  }

  /* ---- Inner class: binary operator type visitor ---- */

  /** Checks the type of a binary operator given unevaluated argument ASTs. */
  class BinOpTypeVisitor implements BinOpVisitor<JamType> {
    private AST arg1, arg2;
    BinOpTypeVisitor(AST a1, AST a2) { arg1 = a1; arg2 = a2; }

    private JamType checkInt(AST a, String op) {
      JamType t = a.accept(TypeChecker.this);
      if (t != IntType.ONLY) throw new TypeException("'" + op + "' requires int, got " + t);
      return IntType.ONLY;
    }
    private JamType checkBool(AST a, String op) {
      JamType t = a.accept(TypeChecker.this);
      if (t != BoolType.ONLY) throw new TypeException("'" + op + "' requires bool, got " + t);
      return BoolType.ONLY;
    }

    public JamType forBinOpPlus()         { checkInt(arg1, "+"); checkInt(arg2, "+"); return IntType.ONLY; }
    public JamType forBinOpMinus()        { checkInt(arg1, "-"); checkInt(arg2, "-"); return IntType.ONLY; }
    public JamType forOpTimes()           { checkInt(arg1, "*"); checkInt(arg2, "*"); return IntType.ONLY; }
    public JamType forOpDivide()          { checkInt(arg1, "/"); checkInt(arg2, "/"); return IntType.ONLY; }
    public JamType forOpLessThan()        { checkInt(arg1, "<"); checkInt(arg2, "<"); return BoolType.ONLY; }
    public JamType forOpGreaterThan()     { checkInt(arg1, ">"); checkInt(arg2, ">"); return BoolType.ONLY; }
    public JamType forOpLessThanEquals()  { checkInt(arg1, "<="); checkInt(arg2, "<="); return BoolType.ONLY; }
    public JamType forOpGreaterThanEquals(){ checkInt(arg1, ">="); checkInt(arg2, ">="); return BoolType.ONLY; }
    public JamType forOpAnd()             { checkBool(arg1, "&"); checkBool(arg2, "&"); return BoolType.ONLY; }
    public JamType forOpOr()              { checkBool(arg1, "|"); checkBool(arg2, "|"); return BoolType.ONLY; }

    /** Polymorphic equality: both args must have the same type. */
    public JamType forOpEquals() {
      JamType t1 = arg1.accept(TypeChecker.this);
      JamType t2 = arg2.accept(TypeChecker.this);
      if (!t1.equals(t2))
        throw new TypeException("'=' requires same type on both sides: " + t1 + " vs " + t2);
      return BoolType.ONLY;
    }
    /** Polymorphic inequality: both args must have the same type. */
    public JamType forOpNotEquals() {
      JamType t1 = arg1.accept(TypeChecker.this);
      JamType t2 = arg2.accept(TypeChecker.this);
      if (!t1.equals(t2))
        throw new TypeException("'!=' requires same type on both sides: " + t1 + " vs " + t2);
      return BoolType.ONLY;
    }
    /** Assignment: ref 'a <- 'a -> unit */
    public JamType forOpGets() {
      JamType t1 = arg1.accept(TypeChecker.this);
      if (!(t1 instanceof RefType))
        throw new TypeException("'<-' requires ref type on left, got " + t1);
      JamType t2 = arg2.accept(TypeChecker.this);
      JamType elemType = ((RefType) t1).elemType();
      if (!t2.equals(elemType))
        throw new TypeException("'<-' type mismatch: ref " + elemType + " but rhs is " + t2);
      return UnitType.ONLY;
    }
  }
}

/** Interpreter for Typed Jam (Assignment 5).
  * Supports two evaluation modes: call-by-value/eager (eagerEval) and
  * call-by-value/lazy (lazyEval, using call-by-need for cons).
  * Type checking is performed before evaluation. */

import java.io.IOException;
import java.io.Reader;


/** The exception class for Jam run-time errors during program evaluation. */
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

/** Interpreter class supporting two forms of evaluation for Typed Jam programs:
  *   eagerEval()  - call-by-value with eager cons
  *   lazyEval()   - call-by-value with lazy (call-by-need) cons */
class Interpreter {
  /** Parser to use. */
  Parser parser;

  /** Parsed and syntax-checked AST. */
  AST prog;

  Interpreter(String fileName) throws IOException {
    parser = new Parser(fileName);
    prog = parser.parseAndCheck();
  }

  Interpreter(Parser p) {
    parser = p;
    prog = parser.parseAndCheck();
  }

  Interpreter(Reader reader) {
    parser = new Parser(reader);
    prog = parser.parseAndCheck();
  }

  /* ---- Public API ---- */

  /** Type checks, then evaluates using call-by-value with eager cons. */
  public JamVal eagerEval() {
    checkTypes(prog);
    return prog.accept(valueValueVisitor);
  }

  /** Type checks, then evaluates using call-by-value with call-by-need cons. */
  public JamVal lazyEval() {
    checkTypes(prog);
    return prog.accept(valueNeedVisitor);
  }

  /** Type checks the given AST.  Throws TypeException on type errors. */
  public void checkTypes(AST ast) {
    ast.accept(new TypeChecker());
  }

  /* ---- Interfaces that support different binding and cons evaluation policies ---- */

  /** The interface supported by various binding evaluation policies. */
  interface BindingPolicy {
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
    Binding newDummyBinding(Variable var);
  }

  /** Interface containing a factory to build the cons object specified by this ConsPolicy. */
  interface ConsPolicy {
    JamVal evalCons(AST[] args, EvalVisitor ev);
  }

  /* Note: Binding is defined in the file ValuesTokens.java */

  /** Class representing a binding in CBV evaluation. */
  static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() {
      if (value == null) illegalForwardReference(var());
      return value;
    }
    public void setBinding(Suspension s) { value = s.eval(); }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** Class representing a binding in CBName evaluation. */
  static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) {
      super(v, null);
      susp = s;
    }
    public JamVal value() { return (susp == null) ? illegalForwardReference(var()) : susp.eval(); }
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }

  /** Class representing a binding in CBNeed evaluation. */
  static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v, s); }
    public JamVal value() {
      if (value == null) {
        if (susp == null) illegalForwardReference(var());
        else {
          value = susp.eval();
          susp = null;
        }
      }
      return value;
    }
    public void setBinding(AST exp, EvalVisitor ev) { susp = new ConcreteSuspension(exp, ev); value = null; }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  /** Helper method supporting Binding classes. */
  static JamVal illegalForwardReference(Variable v) {
    throw new EvalException("Attempt to evaluate variable " + v + " bound to null (illegal forward reference)");
  }

  /** Call-by-value binding policy. */
  static final BindingPolicy CALL_BY_VALUE = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) { return new ValueBinding(var, arg.accept(ev)); }
    public Binding newDummyBinding(Variable var) { return new ValueBinding(var, null); }
  };

  /** Call-by-need binding policy (used only for lazy cons). */
  static final BindingPolicy CALL_BY_NEED = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
    public Binding newDummyBinding(Variable var) { return new NeedBinding(var, null); }
  };

  /** A class representing an unevaluated expression with its evaluator. */
  static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;

    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }

    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }

    public JamVal eval() { return exp.accept(ev); }
    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  /** Class for a lazy cons with call-by-need (memoizing) semantics. */
  static class JamLazyNeedCons extends JamCons {
    protected Suspension firstSusp;
    protected Suspension restSusp;

    public JamLazyNeedCons(AST f, AST r, EvalVisitor ev) {
      super(null, null);
      firstSusp = new ConcreteSuspension(f, ev);
      restSusp  = new ConcreteSuspension(r, ev);
    }

    public JamVal first() {
      if (first == null) { first = firstSusp.eval(); firstSusp = null; }
      return first;
    }

    public JamList rest() {
      if (rest == null) { rest = checkList(restSusp.eval()); restSusp = null; }
      return (JamList) rest;
    }
  }

  /** Eager cons evaluation policy. */
  public static final ConsPolicy EAGER = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) {
      JamVal val0 = args[0].accept(ev);
      JamVal val1 = args[1].accept(ev);
      if (val1 instanceof JamList) return new JamCons(val0, (JamList) val1);
      throw new EvalException("Second argument " + val1 + " to `cons' is not a JamList");
    }
  };

  /** Call-by-need lazy cons evaluation policy. */
  public static final ConsPolicy LAZYNEED = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) { return new JamLazyNeedCons(args[0], args[1], ev); }
  };

  /** Shared visitor instances. */
  static final ASTVisitor<JamVal> valueValueVisitor = new EvalVisitor(CALL_BY_VALUE, EAGER);
  static final ASTVisitor<JamVal> valueNeedVisitor  = new EvalVisitor(CALL_BY_VALUE, LAZYNEED);

  /** Primary visitor class for performing interpretation. */
  static class EvalVisitor implements ASTVisitor<JamVal> {

    PureList<Binding> env;
    BindingPolicy bindingPolicy;
    ConsPolicy consPolicy;

    private EvalVisitor(PureList<Binding> e, BindingPolicy bp, ConsPolicy cp) {
      env = e; bindingPolicy = bp; consPolicy = cp;
    }

    public EvalVisitor(BindingPolicy bp, ConsPolicy cp) { this(new Empty<Binding>(), bp, cp); }

    /** Factory method that constructs a visitor with the given environment. */
    public EvalVisitor newEvalVisitor(PureList<Binding> env) {
      return new EvalVisitor(env, bindingPolicy, consPolicy);
    }

    public PureList<Binding> env() { return env; }

    /* ASTVisitor methods */

    public JamVal forBoolConstant(BoolConstant b) { return b; }
    public JamVal forIntConstant(IntConstant i)   { return i; }
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    public JamVal forVariable(Variable v) {
      Binding match = env.accept(new LookupVisitor<Binding>(v));
      if (match == null) throw new EvalException("variable " + v + " is unbound");
      return match.value();
    }

    public JamVal forPrimFun(PrimFun f) { return f; }
    public JamVal forUnOpApp(UnOpApp u) { return u.rator().accept(new UnOpEvaluator(u.arg().accept(this))); }
    public JamVal forBinOpApp(BinOpApp b) { return b.rator().accept(new BinOpEvaluator(b.arg1(), b.arg2())); }

    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (rator instanceof JamFun)
        return ((JamFun) rator).accept(new FunEvaluator(a.args()));
      throw new EvalException(rator + " appears at head of application but is not a valid function");
    }

    public JamVal forMap(Map m) { return new JamClosure(m, env); }

    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant)) throw new EvalException("non-Boolean " + test + " used as test in if");
      if (test == BoolConstant.TRUE) return i.conseq().accept(this);
      return i.alt().accept(this);
    }

    public JamVal forBlock(Block b) {
      AST[] exps = b.exps();
      if (exps.length == 0) throw new EvalException("Block must contain at least one expression");
      JamVal result = null;
      for (AST e : exps) result = e.accept(this);
      return result;
    }

    /** Recursive let semantics. */
    public JamVal forLet(Let l) {
      Variable[] vars = l.vars();
      AST[]      exps = l.exps();
      int n = vars.length;

      PureList<Binding> newEnv = env();
      Binding[] bindings = new Binding[n];
      for (int i = 0; i < n; i++) {
        bindings[i] = bindingPolicy.newDummyBinding(vars[i]);
        newEnv = newEnv.cons(bindings[i]);
      }
      EvalVisitor newEV = newEvalVisitor(newEnv);
      for (int i = 0; i < n; i++) {
        bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));
      }
      return l.body().accept(newEV);
    }

    /* Inner classes */

    /** Evaluates the application of a function to argument ASTs. */
    class FunEvaluator implements JamFunVisitor<JamVal> {
      AST[] args;
      FunEvaluator(AST[] asts) { args = asts; }

      PrimFunVisitor<JamVal> primEvaluator = new PrimFunVisitor<JamVal>() {

        private JamVal[] evalArgs() {
          int n = args.length;
          JamVal[] vals = new JamVal[n];
          for (int i = 0; i < n; i++) vals[i] = args[i].accept(EvalVisitor.this);
          return vals;
        }

        private void primFunError(String fn) {
          throw new EvalException("Primitive function `" + fn + "' applied to " + args.length + " arguments");
        }

        private JamCons evalJamConsArg(AST arg, String fun) {
          JamVal val = arg.accept(EvalVisitor.this);
          if (val instanceof JamCons) return (JamCons) val;
          throw new EvalException("Primitive `" + fun + "' applied to non-JamCons argument " + val);
        }

        /* Forbidden prims (kept for completeness but should not be reached in typed Jam) */
        public JamVal forFunctionPPrim() { throw new EvalException("function? is not supported in typed Jam"); }
        public JamVal forNumberPPrim()   { throw new EvalException("number? is not supported in typed Jam"); }
        public JamVal forListPPrim()     { throw new EvalException("list? is not supported in typed Jam"); }
        public JamVal forRefPPrim()      { throw new EvalException("ref? is not supported in typed Jam"); }
        public JamVal forArityPrim()     { throw new EvalException("arity is not supported in typed Jam"); }

        public JamVal forConsPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("cons?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
        }

        public JamVal forEmptyPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("empty?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
        }

        public JamVal forConsPrim() {
          if (args.length != 2) primFunError("cons");
          return consPolicy.evalCons(args, EvalVisitor.this);
        }

        public JamVal forFirstPrim() {
          if (args.length != 1) primFunError("first");
          return evalJamConsArg(args[0], "first").first();
        }

        public JamVal forRestPrim() {
          if (args.length != 1) primFunError("rest");
          return evalJamConsArg(args[0], "rest").rest();
        }
      };  // end primEvaluator

      public JamVal forJamClosure(JamClosure closure) {
        Map map = closure.code();
        int n = args.length;
        Variable[] vars = map.vars();
        if (vars.length != n)
          throw new EvalException("closure " + closure + " applied to " + n + " arguments");
        PureList<Binding> newEnv = closure.env();
        for (int i = 0; i < n; i++) {
          newEnv = newEnv.cons(bindingPolicy.newBinding(vars[i], args[i], EvalVisitor.this));
        }
        return map.body().accept(newEvalVisitor(newEnv));
      }

      public JamVal forPrimFun(PrimFun primFun) { return primFun.accept(primEvaluator); }
    }

    /** Evaluator for unary operators. */
    static class UnOpEvaluator implements UnOpVisitor<JamVal> {
      private JamVal val;
      UnOpEvaluator(JamVal jv) { val = jv; }

      private IntConstant checkInteger(String op) {
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-integer " + val);
      }
      private BoolConstant checkBoolean(String op) {
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-boolean " + val);
      }
      private JamRef checkRef(String op) {
        if (val instanceof JamRef) return (JamRef) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-ref " + val);
      }

      public JamVal forUnOpPlus()  { return checkInteger("+"); }
      public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
      public JamVal forOpTilde()   { return checkBoolean("~").not(); }
      public JamVal forOpBang()    { return checkRef("!").value(); }
      public JamVal forOpRef()     { return new JamRef(val); }
    }

    /** Evaluator for binary operators. */
    class BinOpEvaluator implements BinOpVisitor<JamVal> {
      private AST arg1, arg2;
      BinOpEvaluator(AST a1, AST a2) { arg1 = a1; arg2 = a2; }

      private IntConstant evalIntegerArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof IntConstant) return (IntConstant) val;
        throw new EvalException("Binary operator `" + b + "' applied to non-integer " + val);
      }
      private BoolConstant evalBooleanArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof BoolConstant) return (BoolConstant) val;
        throw new EvalException("Binary operator `" + b + "' applied to non-boolean " + val);
      }

      public JamVal forBinOpPlus()  { return new IntConstant(evalIntegerArg(arg1,"+").value() + evalIntegerArg(arg2,"+").value()); }
      public JamVal forBinOpMinus() { return new IntConstant(evalIntegerArg(arg1,"-").value() - evalIntegerArg(arg2,"-").value()); }
      public JamVal forOpTimes()    { return new IntConstant(evalIntegerArg(arg1,"*").value() * evalIntegerArg(arg2,"*").value()); }
      public JamVal forOpDivide() {
        int divisor = evalIntegerArg(arg2, "/").value();
        if (divisor == 0) throw new EvalException("Attempt to divide by zero");
        return new IntConstant(evalIntegerArg(arg1, "/").value() / divisor);
      }
      public JamVal forOpEquals()    { return BoolConstant.toBoolConstant(arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOpNotEquals() { return BoolConstant.toBoolConstant(!arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOpLessThan()        { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,"<").value()  < evalIntegerArg(arg2,"<").value()); }
      public JamVal forOpGreaterThan()     { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,">").value()  > evalIntegerArg(arg2,">").value()); }
      public JamVal forOpLessThanEquals()  { return BoolConstant.toBoolConstant(evalIntegerArg(arg1,"<=").value() <= evalIntegerArg(arg2,"<=").value()); }
      public JamVal forOpGreaterThanEquals(){ return BoolConstant.toBoolConstant(evalIntegerArg(arg1,">=").value() >= evalIntegerArg(arg2,">=").value()); }
      public JamVal forOpAnd() {
        BoolConstant b1 = evalBooleanArg(arg1, "&");
        if (b1 == BoolConstant.FALSE) return BoolConstant.FALSE;
        return evalBooleanArg(arg2, "&");
      }
      public JamVal forOpOr() {
        BoolConstant b1 = evalBooleanArg(arg1, "|");
        if (b1 == BoolConstant.TRUE) return BoolConstant.TRUE;
        return evalBooleanArg(arg2, "|");
      }
      public JamVal forOpGets() {
        JamVal val1 = arg1.accept(EvalVisitor.this);
        if (!(val1 instanceof JamRef))
          throw new EvalException("Binary operator `<-' applied to non-ref " + val1);
        JamVal val2 = arg2.accept(EvalVisitor.this);
        ((JamRef) val1).setValue(val2);
        return JamUnit.ONLY;
      }
    }  // end BinOpEvaluator
  }  // end EvalVisitor
}  // end Interpreter

